/// <summary>
/// Method calls the PurchPurchaseAgreementHeaderV2Entity helper class for the ds - purchAgreementHeader
/// </summary>
public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret;

    ret = next insertEntityDataSource(_entityCtx, _dataSourceCtx);

    if (ret && _dataSourceCtx.name() == dataEntityDataSourceStr(PurchPurchaseAgreementHeaderV2Entity, PurchAgreementHeader) && ETGCanadaParameters::find().EnableIntercompanyB2BSync)
    {
        PurchPurchaseAgreementHeaderV2Entity PurchPurchaseAgreementHeaderV2Entity  = _entityCtx.getEntityRecord();
        PurchAgreementHeader     PurchAgreementHeader     = _dataSourceCtx.getBuffer();

        ETGPurchPurchaseAgreementHeaderV2EntityHelper helper = ETGPurchPurchaseAgreementHeaderV2EntityHelper::construct(PurchAgreementHeader);
        helper.run();
    }
    return ret;
}
